// Ultraheat C4/C6 Radiator Database — generated from manufacturer data
// Output correction: (deltaT/50)^n × W/m × length — EN442
// deltaT = mean water temp − room temp

export type Radiator = {
    id: string
    type: string
    height_mm: number
    length_mm: number
    depth_mm: number
    panels: number
    n: number
    wpm: number  // W/m at deltaT50 (EN442)
  }
  
  export function radOutput(rad: Radiator, deltaT: number): number {
    return Math.round(((deltaT / 50) ** rad.n) * rad.wpm * (rad.length_mm / 1000))
  }
  
  // flowTemp to deltaT: deltaT = ((flow + return) / 2) - roomTemp
  // Typical: flow50/ret40/room21 = deltaT24, flow55/ret45/room21 = deltaT29
  
